#nullable enable
using System;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Show all errors with full context
Console.WriteLine("=== ALL ERRORS (with parent chain) ===");
build.VisitAllChildren<Error>(error =>
{
    var chain = new System.Collections.Generic.List<string>();
    TreeNode? node = error.Parent;
    while (node != null)
    {
        chain.Add($"{node.GetType().Name}: {node}");
        node = node.Parent as TreeNode;
    }
    chain.Reverse();
    Console.WriteLine($"ERROR: {error}");
    Console.WriteLine($"  File: {error.File}");
    Console.WriteLine($"  Line: {error.LineNumber}, Col: {error.ColumnNumber}");
    Console.WriteLine($"  Code: {error.Code}");
    Console.WriteLine($"  Text: {error.Text}");
    Console.WriteLine($"  Subcategory: {error.Subcategory}");
    Console.WriteLine($"  ProjectFile: {error.ProjectFile}");
    Console.WriteLine($"  Chain: {string.Join(" > ", chain)}");
    Console.WriteLine();
});

// Check for MSBuild errors (like MSB3202 for missing project references)
Console.WriteLine("=== SEARCHING FOR MSB ERRORS IN MESSAGES ===");
build.VisitAllChildren<Message>(msg =>
{
    var text = msg.Text ?? "";
    if (text.Contains("MSB") && (text.Contains("error") || text.Contains("Error")))
        Console.WriteLine($"MSG: {text}");
});

// Check for failed targets
Console.WriteLine();
Console.WriteLine("=== FAILED TARGETS / BUILD ERRORS ===");
build.VisitAllChildren<AbstractDiagnostic>(diag =>
{
    Console.WriteLine($"  {diag.GetType().Name}: [{diag.Code}] {diag.Text} (in {diag.ProjectFile})");
});
