#nullable enable
using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Search for the embedded source file records
Console.WriteLine("=== LOOKING FOR CSC TASKS ===");
build.VisitAllChildren<CscTask>(csc =>
{
    TreeNode? node = csc.Parent;
    string projName = "";
    while (node != null)
    {
        if (node is Project p) { projName = p.Name; break; }
        node = node.Parent as TreeNode;
    }
    Console.WriteLine($"\nCsc task for {projName}");
    if (csc.HasChildren)
    {
        foreach (var child in csc.Children)
        {
            var t = child.ToString() ?? "";
            if (t.Contains(".cs") || t.Contains("Source"))
                Console.WriteLine($"  ({child.GetType().Name}): {t.Substring(0, Math.Min(200, t.Length))}");
        }
    }
});

// Look for SourceFile nodes with content via raw binary log reader
Console.WriteLine("\n=== USING RAW READER FOR EMBEDDED FILES ===");
var reader = new BinLogReader();
var records = reader.ReadRecords(binlogPath).ToList();
Console.WriteLine($"Total records: {records.Count}");

foreach (var record in records)
{
    if (record.Args is Microsoft.Build.Framework.BuildMessageEventArgs msg)
    {
        var text = msg.Message ?? "";
        if (text.Contains("UserService.cs") && !text.Contains("BuildResponseFile") && text.Length < 500)
            Console.WriteLine($"  Msg about UserService: {text}");
        if (text.Contains("Models.cs") && !text.Contains("BuildResponseFile") && text.Length < 500)
            Console.WriteLine($"  Msg about Models: {text}");
    }
    if (record.Args is Microsoft.Build.Framework.BuildErrorEventArgs err)
    {
        Console.WriteLine($"  ERROR [{err.Code}] {err.File}({err.LineNumber},{err.ColumnNumber}): {err.Message}");
    }
}
